152.                .Single();
153. 
154.             if (await TryUpdateModelAsync<Instructor>(instructorToUpdate, "", i => i.LastName, i => i.FirstMidName, i => i.HireDate, i => i.OfficeAssignment))
155.             {
156.                 try
157.                 {
158.                     if (string.IsNullOrWhiteSpace(instructorToUpdate.OfficeAssignment?.Location))
159.                     {
160.                         instructorToUpdate.OfficeAssignment = null;
161.                     }
162. 
163.                     UpdateInstructorCourses(selectedCourses, instructorToUpdate);
164. 
165.                     db.SaveChanges();
166.                     SendEntityNotification("Instructor", instructorToUpdate.ID.ToString(), EntityOperation.UPDATE);
167.                     return RedirectToAction("Index");
168.                 }
169.                 catch (Exception)
170.                 {
171.                     ModelState.AddModelError("", "Unable to save changes. Try again, and if the problem persists, see your system administrator.");
172.                 }
173.             }
174.             PopulateAssignedCourseData(instructorToUpdate);
175.             return View(instructorToUpdate);
176.         }
177. 
178.         private void UpdateInstructorCourses(string[] selectedCourses, Instructor instructorToUpdate)
179.         {
180.             if (selectedCourses == null)
181.             {
182.                 instructorToUpdate.CourseAssignments = new List<CourseAssignment>();
183.                 return;
184.             }
185. 
186.             var selectedCoursesHS = new HashSet<string>(selectedCourses);
187.             var instructorCourses = new HashSet<int>
188.                 (instructorToUpdate.CourseAssignments.Select(c => c.Course.CourseID));
189.             foreach (var course in db.Courses)
190.             {
191.                 if (selectedCoursesHS.Contains(course.CourseID.ToString()))
192.                 {
193.                     if (!instructorCourses.Contains(course.CourseID))
194.                     {
195.                         instructorToUpdate.CourseAssignments.Add(new CourseAssignment { InstructorID = instructorToUpdate.ID, CourseID = course.CourseID });
196.                     }
197.                 }
198.                 else
199.                 {
200. 
201.                     if (instructorCourses.Contains(course.CourseID))
202.                     {
203.                         CourseAssignment courseToRemove = instructorToUpdate.CourseAssignments.SingleOrDefault(i => i.CourseID == course.CourseID);
204.                         db.Entry(courseToRemove).State = EntityState.Deleted;
205.                     }
205.                 }
206.             }
207.         }
