5. namespace ContosoUniversity.Services
6. {
7.     public class NotificationService : IDisposable
8.     {
9.         // Static shared queue across application instances (simple in-memory alternative to MSMQ)
10.         private static readonly ConcurrentQueue<Notification> _queue = new();
11.         private static readonly int _maxQueueLength = 500; // basic cap to prevent unbounded growth
12. 
13.         public NotificationService()
14.         {
15.             // No initialization required for in-memory queue
16.         }
17. 
18.         public void SendNotification(string entityType, string entityId, EntityOperation operation, string userName = null)
19.         {
20.             SendNotification(entityType, entityId, null, operation, userName);
21.         }
22. 
23.         public void SendNotification(string entityType, string entityId, string entityDisplayName, EntityOperation operation, string userName = null)
24.         {
24.             try
25.             {
26.                 var notification = new Notification
27.                 {
28.                     EntityType = entityType,
29.                     EntityId = entityId,
30.                     Operation = operation.ToString(),
31.                     Message = GenerateMessage(entityType, entityId, entityDisplayName, operation),
32.                     CreatedAt = DateTime.Now,
33.                     CreatedBy = userName ?? "System",
34.                     IsRead = false
35.                 };
36. 
37.                 _queue.Enqueue(notification);
38. 
39.                 // Enforce max queue length (best-effort)
40.                 while (_queue.Count > _maxQueueLength && _queue.TryDequeue(out _)) { }
41.             }
42.             catch (Exception ex)
43.             {
44.                 System.Diagnostics.Debug.WriteLine($"Failed to enqueue notification: {ex.Message}");
45.             }
46.         }
47. 
48.         public Notification ReceiveNotification()
49.         {
50.             try
51.             {
52.                 return _queue.TryDequeue(out var notification) ? notification : null;
53.             }
54.             catch (Exception ex)
55.             {
56.                 System.Diagnostics.Debug.WriteLine($"Failed to receive notification: {ex.Message}");
57.                 return null;
58.             }
59.         }
60. 
61.         public void MarkAsRead(int notificationId)
62.         {
62.             // No-op for in-memory implementation (persistence not implemented)
63.         }
64. 
65.         private string GenerateMessage(string entityType, string entityId, string entityDisplayName, EntityOperation operation)
66.         {
66.             var displayText = !string.IsNullOrWhiteSpace(entityDisplayName)
67.                 ? $"{entityType} '{entityDisplayName}'"
68.                 : $"{entityType} (ID: {entityId})";
69. 
70.             return operation switch
71.             {
72.                 EntityOperation.CREATE => $"New {displayText} has been created",
73.                 EntityOperation.UPDATE => $"{displayText} has been updated",
74.                 EntityOperation.DELETE => $"{displayText} has been deleted",
75.                 _ => $"{displayText} operation: {operation}"
76.             };
77.         }
78. 
79.         public void Dispose()
80.         {
80.             // Nothing to dispose for in-memory queue
81.         }
82.     }
83. }
