using ContosoUniversity.Models;
using System.Collections.Generic;
using System.ComponentModel.DataAnnotations;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Models
{
    public class CourseTests
    {
        [Fact]
        public void Course_Properties_SetAndGet()
        {
            var course = new Course
            {
                CourseID = 1050,
                Title = "Chemistry",
                Credits = 3,
                DepartmentID = 1,
                TeachingMaterialImagePath = "/uploads/test.jpg"
            };

            Assert.Equal(1050, course.CourseID);
            Assert.Equal("Chemistry", course.Title);
            Assert.Equal(3, course.Credits);
            Assert.Equal(1, course.DepartmentID);
            Assert.Equal("/uploads/test.jpg", course.TeachingMaterialImagePath);
        }

        [Fact]
        public void Course_NavigationProperties_Initialized()
        {
            var course = new Course
            {
                Enrollments = new List<Enrollment>(),
                CourseAssignments = new List<CourseAssignment>(),
                Department = new Department { Name = "Test" }
            };

            Assert.NotNull(course.Enrollments);
            Assert.NotNull(course.CourseAssignments);
            Assert.NotNull(course.Department);
        }

        [Theory]
        [InlineData(0, true)]
        [InlineData(3, true)]
        [InlineData(5, true)]
        [InlineData(-1, false)]
        [InlineData(6, false)]
        public void Course_Credits_RangeValidation(int credits, bool isValid)
        {
            var course = new Course { CourseID = 1, Title = "Test", Credits = credits, DepartmentID = 1 };
            var context = new ValidationContext(course);
            var results = new List<ValidationResult>();
            var valid = Validator.TryValidateObject(course, context, results, true);

            Assert.Equal(isValid, valid || !results.Any(r => r.MemberNames.Contains("Credits")));
        }

        [Theory]
        [InlineData("AB", false)]
        [InlineData("ABC", true)]
        [InlineData("Valid Title", true)]
        public void Course_Title_LengthValidation(string title, bool isValid)
        {
            var course = new Course { CourseID = 1, Title = title, Credits = 3, DepartmentID = 1 };
            var context = new ValidationContext(course);
            var results = new List<ValidationResult>();
            Validator.TryValidateObject(course, context, results, true);

            if (isValid)
                Assert.DoesNotContain(results, r => r.MemberNames.Contains("Title"));
            else
                Assert.Contains(results, r => r.MemberNames.Contains("Title"));
        }
    }
}

using ContosoUniversity.Models;
using System;
using System.Collections.Generic;
using System.ComponentModel.DataAnnotations;
using Xunit;

namespace ContosoUniversity.Tests.Models
{
    public class DepartmentTests
    {
        [Fact]
        public void Department_Properties_SetAndGet()
        {
            var date = DateTime.Parse("2007-09-01");
            var dept = new Department
            {
                DepartmentID = 1,
                Name = "Engineering",
                Budget = 350000m,
                StartDate = date,
                InstructorID = 5,
                RowVersion = new byte[] { 1, 2, 3 }
            };

            Assert.Equal(1, dept.DepartmentID);
            Assert.Equal("Engineering", dept.Name);
            Assert.Equal(350000m, dept.Budget);
            Assert.Equal(date, dept.StartDate);
            Assert.Equal(5, dept.InstructorID);
            Assert.Equal(new byte[] { 1, 2, 3 }, dept.RowVersion);
        }

        [Fact]
        public void Department_InstructorID_CanBeNull()
        {
            var dept = new Department { Name = "Test", InstructorID = null };
            Assert.Null(dept.InstructorID);
        }

        [Fact]
        public void Department_NavigationProperties()
        {
            var dept = new Department
            {
                Administrator = new Instructor { FirstMidName = "Kim", LastName = "A" },
                Courses = new List<Course>()
            };

            Assert.NotNull(dept.Administrator);
            Assert.NotNull(dept.Courses);
        }

        [Theory]
        [InlineData("AB", false)]
        [InlineData("ABC", true)]
        [InlineData("Valid Department", true)]
        public void Department_Name_LengthValidation(string name, bool isValid)
        {
            var dept = new Department { Name = name, Budget = 100, StartDate = DateTime.Now };
            var context = new ValidationContext(dept);
            var results = new List<ValidationResult>();
            Validator.TryValidateObject(dept, context, results, true);

            if (isValid)
                Assert.DoesNotContain(results, r => r.MemberNames.Contains("Name"));
            else
                Assert.Contains(results, r => r.MemberNames.Contains("Name"));
        }
    }
}

