        {
            var course = new Course
            {
                CourseID = 1050,
                Title = "Chemistry",
                Credits = 3,
                DepartmentID = 1,
                TeachingMaterialImagePath = "/uploads/test.jpg"
            };

            Assert.Equal(1050, course.CourseID);
            Assert.Equal("Chemistry", course.Title);
            Assert.Equal(3, course.Credits);
            Assert.Equal(1, course.DepartmentID);
            Assert.Equal("/uploads/test.jpg", course.TeachingMaterialImagePath);
        }

        [Fact]
        public void Course_NavigationProperties_Initialized()
        {
            var course = new Course
            {
                Enrollments = new List<Enrollment>(),
                CourseAssignments = new List<CourseAssignment>(),
                Department = new Department { Name = "Test" }
            };

            Assert.NotNull(course.Enrollments);
            Assert.NotNull(course.CourseAssignments);
            Assert.NotNull(course.Department);
        }

        [Theory]
        [InlineData(0, true)]
        [InlineData(3, true)]
        [InlineData(5, true)]
        [InlineData(-1, false)]
        [InlineData(6, false)]
        public void Course_Credits_RangeValidation(int credits, bool isValid)
        {
            var course = new Course { CourseID = 1, Title = "Test", Credits = credits, DepartmentID = 1 };
            var context = new ValidationContext(course);
            var results = new List<ValidationResult>();
            var valid = Validator.TryValidateObject(course, context, results, true);

            Assert.Equal(isValid, valid || !results.Any(r => r.MemberNames.Contains("Credits")));
        }

