        [InlineData("AB", false)]
        [InlineData("ABC", true)]
        [InlineData("Valid Title", true)]
        public void Course_Title_LengthValidation(string title, bool isValid)
        {
            var course = new Course { CourseID = 1, Title = title, Credits = 3, DepartmentID = 1 };
            var context = new ValidationContext(course);
            var results = new List<ValidationResult>();
            Validator.TryValidateObject(course, context, results, true);

            if (isValid)
                Assert.DoesNotContain(results, r => r.MemberNames.Contains("Title"));
            else
                Assert.Contains(results, r => r.MemberNames.Contains("Title"));
        }
    }
}
