using ContosoUniversity.Models;
using System;
using System.Collections.Generic;
using Xunit;

namespace ContosoUniversity.Tests.Models
{
    public class InstructorTests
    {
        [Fact]
        public void Instructor_InheritsFromPerson()
        {
            var instructor = new Instructor();
            Assert.IsAssignableFrom<Person>(instructor);
        }

        [Fact]
        public void Instructor_Properties_SetAndGet()
        {
            var hireDate = DateTime.Parse("2000-01-15");
            var instructor = new Instructor
            {
                ID = 1,
                FirstMidName = "Kim",
                LastName = "Abercrombie",
                HireDate = hireDate
            };

            Assert.Equal(1, instructor.ID);
            Assert.Equal("Kim", instructor.FirstMidName);
            Assert.Equal("Abercrombie", instructor.LastName);
            Assert.Equal(hireDate, instructor.HireDate);
            Assert.Equal("Abercrombie, Kim", instructor.FullName);
        }

        [Fact]
        public void Instructor_NavigationProperties()
        {
            var instructor = new Instructor
            {
                CourseAssignments = new List<CourseAssignment>(),
                OfficeAssignment = new OfficeAssignment { Location = "Room 101" }
            };

            Assert.NotNull(instructor.CourseAssignments);
            Assert.Empty(instructor.CourseAssignments);
            Assert.Equal("Room 101", instructor.OfficeAssignment.Location);
        }
    }
}

