using ContosoUniversity.Models;
using ContosoUniversity.Services;
using System;
using Xunit;

namespace ContosoUniversity.Tests.Services
{
    public class NotificationServiceTests : IDisposable
    {
        private readonly NotificationService _service;

        public NotificationServiceTests()
        {
            _service = new NotificationService();
            // Drain any leftover notifications from static queue
            while (_service.ReceiveNotification() != null) { }
        }

        public void Dispose()
        {
            _service.Dispose();
        }

        [Fact]
        public void SendNotification_WithDisplayName_EnqueuesNotification()
        {
            _service.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE, "Admin");

            var notification = _service.ReceiveNotification();

            Assert.NotNull(notification);
            Assert.Equal("Student", notification.EntityType);
            Assert.Equal("1", notification.EntityId);
            Assert.Equal("CREATE", notification.Operation);
            Assert.Contains("John Doe", notification.Message);
            Assert.Contains("created", notification.Message);
            Assert.Equal("Admin", notification.CreatedBy);
            Assert.False(notification.IsRead);
        }

        [Fact]
        public void SendNotification_WithoutDisplayName_UsesIdInMessage()
        {
            _service.SendNotification("Course", "42", EntityOperation.UPDATE, "System");

            var notification = _service.ReceiveNotification();

            Assert.NotNull(notification);
            Assert.Contains("ID: 42", notification.Message);
            Assert.Contains("updated", notification.Message);
        }

        [Fact]
        public void SendNotification_Delete_GeneratesDeleteMessage()
        {
            _service.SendNotification("Department", "5", "Engineering", EntityOperation.DELETE);

            var notification = _service.ReceiveNotification();

            Assert.NotNull(notification);
            Assert.Equal("DELETE", notification.Operation);
            Assert.Contains("deleted", notification.Message);
            Assert.Contains("Engineering", notification.Message);
        }

        [Fact]
        public void SendNotification_NullUserName_DefaultsToSystem()
        {
            _service.SendNotification("Student", "1", EntityOperation.CREATE);

            var notification = _service.ReceiveNotification();

            Assert.NotNull(notification);
            Assert.Equal("System", notification.CreatedBy);
        }

        [Fact]
        public void ReceiveNotification_EmptyQueue_ReturnsNull()
        {
            var notification = _service.ReceiveNotification();
            Assert.Null(notification);
        }

        [Fact]
        public void ReceiveNotification_FIFO_Order()
        {
            _service.SendNotification("A", "1", EntityOperation.CREATE);
            _service.SendNotification("B", "2", EntityOperation.UPDATE);
            _service.SendNotification("C", "3", EntityOperation.DELETE);

            var first = _service.ReceiveNotification();
            var second = _service.ReceiveNotification();
            var third = _service.ReceiveNotification();

            Assert.Equal("A", first.EntityType);
            Assert.Equal("B", second.EntityType);
            Assert.Equal("C", third.EntityType);
        }

        [Fact]
        public void ReceiveNotification_RemovesFromQueue()
        {
            _service.SendNotification("Student", "1", EntityOperation.CREATE);

            var first = _service.ReceiveNotification();
            var second = _service.ReceiveNotification();

            Assert.NotNull(first);
            Assert.Null(second);
        }

        [Fact]
        public void MarkAsRead_DoesNotThrow()
        {
            // MarkAsRead is a no-op for in-memory implementation
            var ex = Record.Exception(() => _service.MarkAsRead(1));
            Assert.Null(ex);
        }

        [Fact]
        public void SendNotification_Create_MessageFormat()
        {
            _service.SendNotification("Student", "1", "Alice Smith", EntityOperation.CREATE);
            var n = _service.ReceiveNotification();
            Assert.Equal("New Student 'Alice Smith' has been created", n.Message);
        }

        [Fact]
        public void SendNotification_Update_MessageFormat()
        {
            _service.SendNotification("Course", "5", "Physics", EntityOperation.UPDATE);
            var n = _service.ReceiveNotification();
            Assert.Equal("Course 'Physics' has been updated", n.Message);
        }

        [Fact]
        public void SendNotification_Delete_MessageFormat()
        {
            _service.SendNotification("Department", "3", "Math", EntityOperation.DELETE);
            var n = _service.ReceiveNotification();
            Assert.Equal("Department 'Math' has been deleted", n.Message);
        }

        [Fact]
        public void SendNotification_WithoutDisplayName_MessageFormat()
        {
            _service.SendNotification("Student", "99", EntityOperation.CREATE);
            var n = _service.ReceiveNotification();
            Assert.Equal("New Student (ID: 99) has been created", n.Message);
        }

        [Fact]
        public void SendNotification_SetsCreatedAt()
        {
            var before = DateTime.Now;
            _service.SendNotification("Student", "1", EntityOperation.CREATE);
            var after = DateTime.Now;

            var notification = _service.ReceiveNotification();
            Assert.InRange(notification.CreatedAt, before, after);
        }

        [Fact]
        public void Dispose_DoesNotThrow()
        {
            var service = new NotificationService();
            var ex = Record.Exception(() => service.Dispose());
            Assert.Null(ex);
        }
    }
}

using System.Collections.Generic;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests
{
    public class PaginatedListTests
    {
        [Fact]
        public void Constructor_SetsPageIndex()
        {
            var items = new List<int> { 1, 2, 3 };
            var list = new PaginatedList<int>(items, 10, 2, 3);

            Assert.Equal(2, list.PageIndex);
        }

        [Fact]
        public void Constructor_CalculatesTotalPages()
        {
            var items = new List<int> { 1, 2, 3 };
            var list = new PaginatedList<int>(items, 10, 1, 3);

            Assert.Equal(4, list.TotalPages); // ceil(10/3) = 4
        }

        [Fact]
        public void Constructor_AddsItemsToList()
        {
            var items = new List<string> { "a", "b", "c" };
            var list = new PaginatedList<string>(items, 5, 1, 3);

            Assert.Equal(3, list.Count);
            Assert.Contains("a", list);
            Assert.Contains("b", list);
            Assert.Contains("c", list);
        }

        [Fact]
        public void HasPreviousPage_FirstPage_ReturnsFalse()
        {
            var list = new PaginatedList<int>(new List<int>(), 10, 1, 5);
            Assert.False(list.HasPreviousPage);
        }

        [Fact]
        public void HasPreviousPage_SecondPage_ReturnsTrue()
        {
            var list = new PaginatedList<int>(new List<int>(), 10, 2, 5);
            Assert.True(list.HasPreviousPage);
        }

        [Fact]
        public void HasNextPage_LastPage_ReturnsFalse()
        {
            var list = new PaginatedList<int>(new List<int>(), 10, 2, 5);
            // TotalPages = ceil(10/5) = 2, PageIndex = 2
            Assert.False(list.HasNextPage);
        }

        [Fact]
        public void HasNextPage_FirstPage_ReturnsTrue()
        {
            var list = new PaginatedList<int>(new List<int>(), 10, 1, 5);
            Assert.True(list.HasNextPage);
        }

        [Fact]
        public void Create_ReturnsCorrectPage()
        {
            var source = Enumerable.Range(1, 25).AsQueryable();

            var page1 = PaginatedList<int>.Create(source, 1, 10);
            Assert.Equal(10, page1.Count);
            Assert.Equal(1, page1.First());
            Assert.Equal(10, page1.Last());
            Assert.Equal(1, page1.PageIndex);
            Assert.Equal(3, page1.TotalPages);
        }

        [Fact]
        public void Create_SecondPage_SkipsFirst()
        {
            var source = Enumerable.Range(1, 25).AsQueryable();

            var page2 = PaginatedList<int>.Create(source, 2, 10);
            Assert.Equal(10, page2.Count);
            Assert.Equal(11, page2.First());
            Assert.Equal(20, page2.Last());
        }

        [Fact]
        public void Create_LastPage_PartialResults()
        {
            var source = Enumerable.Range(1, 25).AsQueryable();

            var page3 = PaginatedList<int>.Create(source, 3, 10);
            Assert.Equal(5, page3.Count);
            Assert.Equal(21, page3.First());
            Assert.Equal(25, page3.Last());
        }

        [Fact]
        public void TotalPages_ExactDivision()
        {
            var list = new PaginatedList<int>(new List<int>(), 20, 1, 10);
            Assert.Equal(2, list.TotalPages);
        }

        [Fact]
        public void TotalPages_SingleItem()
        {
            var list = new PaginatedList<int>(new List<int>(), 1, 1, 10);
            Assert.Equal(1, list.TotalPages);
        }

        [Fact]
        public void TotalPages_EmptyCollection()
        {
            var list = new PaginatedList<int>(new List<int>(), 0, 1, 10);
            Assert.Equal(0, list.TotalPages);
        }
    }
}

