using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Hosting;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;
using Microsoft.Extensions.Logging;
using Moq;
using System;
using System.Collections.Generic;
using System.IO;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class CoursesControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly CoursesController _controller;
        private readonly Mock<IWebHostEnvironment> _envMock;
        private readonly Mock<ILogger<CoursesController>> _loggerMock;
        private readonly string _tempDir;

        public CoursesControllerTests()
        {
            _context = TestDbContextFactory.CreateSeeded();
            _envMock = new Mock<IWebHostEnvironment>();
            _loggerMock = new Mock<ILogger<CoursesController>>();

            _tempDir = Path.Combine(Path.GetTempPath(), Guid.NewGuid().ToString());
            Directory.CreateDirectory(_tempDir);
            _envMock.Setup(e => e.WebRootPath).Returns(_tempDir);
            _envMock.Setup(e => e.ContentRootPath).Returns(_tempDir);

            _controller = new CoursesController(_context, _envMock.Object, _loggerMock.Object);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
            if (Directory.Exists(_tempDir))
            {
                try { Directory.Delete(_tempDir, true); } catch { }
            }
        }

        #region Index

        [Fact]
        public void Index_ReturnsViewResult_WithCourses()
        {
            var result = _controller.Index() as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsAssignableFrom<List<Course>>(result.Model);
            Assert.Equal(2, model.Count);
        }

        #endregion

        #region Details

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Details_ValidId_ReturnsViewWithCourse()
        {
            var course = _context.Courses.First();

            var result = _controller.Details(course.CourseID) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Course>(result.Model);
            Assert.Equal(course.CourseID, model.CourseID);
        }

        #endregion

        #region Create GET

        [Fact]
        public void Create_GET_ReturnsViewResult_WithDepartmentSelectList()
        {
            var result = _controller.Create() as ViewResult;

            Assert.NotNull(result);
            Assert.NotNull(_controller.ViewBag.DepartmentID);
            var model = Assert.IsType<Course>(result.Model);
        }

        #endregion

        #region Create POST

        [Fact]
        public void Create_POST_ValidCourse_NoImage_RedirectsToIndex()
        {
            var course = new Course
            {
                CourseID = 9999,
                Title = "New Course",
                Credits = 3,
                DepartmentID = _context.Departments.First().DepartmentID
            };

            var result = _controller.Create(course, null) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
        }

        [Fact]
        public void Create_POST_ValidCourse_AddsToDatabase()
        {
            var countBefore = _context.Courses.Count();
            var course = new Course
            {
                CourseID = 8888,
                Title = "Test Course",
                Credits = 4,
                DepartmentID = _context.Departments.First().DepartmentID
            };

            _controller.Create(course, null);

            Assert.Equal(countBefore + 1, _context.Courses.Count());
        }

        [Fact]
        public void Create_POST_InvalidModel_ReturnsView()
        {
            _controller.ModelState.AddModelError("Title", "Required");

            var course = new Course { CourseID = 1, Credits = 3 };
            var result = _controller.Create(course, null) as ViewResult;

            Assert.NotNull(result);
            Assert.NotNull(_controller.ViewBag.DepartmentID);
        }

        [Fact]
        public void Create_POST_InvalidFileExtension_ReturnsViewWithError()
        {
            var fileMock = CreateMockFile("test.exe", 1024);
            var course = new Course
            {
                CourseID = 7777,
                Title = "Test",
                Credits = 3,
                DepartmentID = _context.Departments.First().DepartmentID
            };

            var result = _controller.Create(course, fileMock.Object) as ViewResult;

            Assert.NotNull(result);
            Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [Fact]
        public void Create_POST_FileTooLarge_ReturnsViewWithError()
        {
            var fileMock = CreateMockFile("test.jpg", 6 * 1024 * 1024); // 6MB
            var course = new Course
            {
                CourseID = 6666,
                Title = "Test",
                Credits = 3,
                DepartmentID = _context.Departments.First().DepartmentID
            };

            var result = _controller.Create(course, fileMock.Object) as ViewResult;

            Assert.NotNull(result);
            Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [Fact]
        public void Create_POST_ValidImage_UploadsFile()
        {
            var fileMock = CreateMockFile("material.png", 1024);
            var course = new Course
            {
                CourseID = 5555,
                Title = "Upload Test",
                Credits = 3,
                DepartmentID = _context.Departments.First().DepartmentID
            };

            var result = _controller.Create(course, fileMock.Object) as RedirectToActionResult;

            Assert.NotNull(result);
            var savedCourse = _context.Courses.Find(5555);
            Assert.NotNull(savedCourse.TeachingMaterialImagePath);
            Assert.Contains("/Uploads/TeachingMaterials/", savedCourse.TeachingMaterialImagePath);
        }

        #endregion

        #region Edit GET

        [Fact]
        public void Edit_GET_NullId_ReturnsBadRequest()
        {
            var result = _controller.Edit((int?)null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Edit_GET_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Edit(99999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Edit_GET_ValidId_ReturnsViewWithCourse()
        {
            var course = _context.Courses.First();

            var result = _controller.Edit(course.CourseID) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Course>(result.Model);
            Assert.Equal(course.CourseID, model.CourseID);
        }

        #endregion

        #region Edit POST

        [Fact]
        public void Edit_POST_ValidCourse_NoImage_RedirectsToIndex()
        {
            var course = _context.Courses.AsNoTracking().First();
            course.Title = "Updated";

            var result = _controller.Edit(course, null) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
        }

        [Fact]
        public void Edit_POST_ValidCourse_UpdatesDatabase()
        {
            var course = _context.Courses.AsNoTracking().First();
            course.Title = "Modified Title";

            _controller.Edit(course, null);

            var updated = _context.Courses.Find(course.CourseID);
            Assert.Equal("Modified Title", updated.Title);
        }

        [Fact]
        public void Edit_POST_InvalidModel_ReturnsView()
        {
            _controller.ModelState.AddModelError("Title", "Required");

            var course = _context.Courses.AsNoTracking().First();
            var result = _controller.Edit(course, null) as ViewResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void Edit_POST_InvalidFileExtension_ReturnsError()
        {
            var fileMock = CreateMockFile("bad.txt", 1024);
            var course = _context.Courses.AsNoTracking().First();

            var result = _controller.Edit(course, fileMock.Object) as ViewResult;

            Assert.NotNull(result);
            Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [Fact]
        public void Edit_POST_FileTooLarge_ReturnsError()
        {
            var fileMock = CreateMockFile("big.jpg", 6 * 1024 * 1024);
            var course = _context.Courses.AsNoTracking().First();

            var result = _controller.Edit(course, fileMock.Object) as ViewResult;

            Assert.NotNull(result);
            Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [Fact]
        public void Edit_POST_ValidImage_UploadsAndUpdates()
        {
            var fileMock = CreateMockFile("new_image.jpg", 2048);
            var course = _context.Courses.AsNoTracking().First();

            var result = _controller.Edit(course, fileMock.Object) as RedirectToActionResult;

            Assert.NotNull(result);
            var updated = _context.Courses.Find(course.CourseID);
            Assert.Contains("/Uploads/TeachingMaterials/", updated.TeachingMaterialImagePath);
        }

        #endregion

        #region Delete GET

        [Fact]
        public void Delete_GET_NullId_ReturnsBadRequest()
        {
            var result = _controller.Delete(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Delete_GET_ValidId_ReturnsViewWithCourse()
        {
            var course = _context.Courses.First();

            var result = _controller.Delete(course.CourseID) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Course>(result.Model);
            Assert.Equal(course.CourseID, model.CourseID);
        }

        #endregion

        #region Delete POST

        [Fact]
        public void DeleteConfirmed_ValidId_RedirectsToIndex()
        {
            var course = _context.Courses.First();

            var result = _controller.DeleteConfirmed(course.CourseID) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
        }

        [Fact]
        public void DeleteConfirmed_ValidId_RemovesFromDatabase()
        {
            var course = _context.Courses.First();
            var countBefore = _context.Courses.Count();

            _controller.DeleteConfirmed(course.CourseID);

            Assert.Equal(countBefore - 1, _context.Courses.Count());
        }

        #endregion

        #region Helpers

        private Mock<IFormFile> CreateMockFile(string fileName, long length)
        {
            var fileMock = new Mock<IFormFile>();
            var ms = new MemoryStream(new byte[length]);
            fileMock.Setup(f => f.FileName).Returns(fileName);
            fileMock.Setup(f => f.Length).Returns(length);
            fileMock.Setup(f => f.CopyTo(It.IsAny<Stream>()))
                    .Callback<Stream>(s => ms.CopyTo(s));
            return fileMock;
        }

        #endregion
    }
}

