using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;
using System;
using System.Collections.Generic;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class InstructorsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly InstructorsController _controller;

        public InstructorsControllerTests()
        {
            _context = TestDbContextFactory.CreateSeeded();
            _controller = new InstructorsController(_context);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        #region Index

        [Fact]
        public void Index_ReturnsViewResult_WithInstructorIndexData()
        {
            var result = _controller.Index(null, null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<InstructorIndexData>(result.Model);
            Assert.NotNull(model.Instructors);
            Assert.Equal(2, model.Instructors.Count());
        }

        [Fact]
        public void Index_WithInstructorId_PopulatesCourses()
        {
            var instructor = _context.Instructors.First();

            var result = _controller.Index(instructor.ID, null) as ViewResult;

            var model = Assert.IsType<InstructorIndexData>(result.Model);
            Assert.NotNull(model.Courses);
        }

        [Fact]
        public void Index_InstructorsOrderedByLastName()
        {
            var result = _controller.Index(null, null) as ViewResult;

            var model = Assert.IsType<InstructorIndexData>(result.Model);
            var instructors = model.Instructors.ToList();
            Assert.Equal("Abercrombie", instructors[0].LastName);
            Assert.Equal("Fakhouri", instructors[1].LastName);
        }

        #endregion

        #region Details

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Details_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Details(99999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Details_ValidId_ReturnsViewWithInstructor()
        {
            var instructor = _context.Instructors.First();

            var result = _controller.Details(instructor.ID) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Instructor>(result.Model);
            Assert.Equal(instructor.ID, model.ID);
        }

        #endregion

        #region Create GET

        [Fact]
        public void Create_GET_ReturnsViewResult_WithNewInstructor()
        {
            var result = _controller.Create() as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Instructor>(result.Model);
            Assert.NotNull(model.CourseAssignments);
            Assert.NotNull(_controller.ViewBag.Courses);
        }

        [Fact]
        public void Create_GET_PopulatesAssignedCourseData()
        {
            var result = _controller.Create() as ViewResult;

            var courses = _controller.ViewBag.Courses as List<AssignedCourseData>;
            Assert.NotNull(courses);
            Assert.Equal(2, courses.Count);
            Assert.All(courses, c => Assert.False(c.Assigned));
        }

        #endregion

        #region Create POST

        [Fact]
        public void Create_POST_ValidInstructor_RedirectsToIndex()
        {
            var instructor = new Instructor
            {
                FirstMidName = "New",
                LastName = "Instructor",
                HireDate = DateTime.Parse("2020-01-01")
            };

            var result = _controller.Create(instructor, null) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
        }

        [Fact]
        public void Create_POST_ValidInstructor_AddsToDatabase()
        {
            var countBefore = _context.Instructors.Count();

            var instructor = new Instructor
            {
                FirstMidName = "Test",
                LastName = "Teacher",
                HireDate = DateTime.Parse("2020-06-15")
            };

            _controller.Create(instructor, null);

            Assert.Equal(countBefore + 1, _context.Instructors.Count());
        }

        [Fact]
        public void Create_POST_WithSelectedCourses_AddsCourseAssignments()
        {
            var courseIds = _context.Courses.Select(c => c.CourseID.ToString()).ToArray();

            var instructor = new Instructor
            {
                FirstMidName = "Course",
                LastName = "Assigner",
                HireDate = DateTime.Parse("2020-01-01")
            };

            _controller.Create(instructor, courseIds);

            var saved = _context.Instructors
                .Include(i => i.CourseAssignments)
                .Single(i => i.LastName == "Assigner");
            Assert.Equal(courseIds.Length, saved.CourseAssignments.Count);
        }

        [Fact]
        public void Create_POST_InvalidModel_ReturnsView()
        {
            _controller.ModelState.AddModelError("LastName", "Required");

            var instructor = new Instructor { HireDate = DateTime.Now };
            var result = _controller.Create(instructor, null) as ViewResult;

            Assert.NotNull(result);
        }

        #endregion

        #region Edit GET

        [Fact]
        public void Edit_GET_NullId_ReturnsBadRequest()
        {
            var result = _controller.Edit((int?)null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Edit_GET_ValidId_ReturnsViewWithInstructor()
        {
            var instructor = _context.Instructors
                .Include(i => i.CourseAssignments).ThenInclude(ca => ca.Course)
                .Include(i => i.OfficeAssignment)
                .First();

            var result = _controller.Edit(instructor.ID) as ViewResult;

            Assert.NotNull(result);
            Assert.NotNull(_controller.ViewBag.Courses);
        }

        #endregion

        #region Delete GET

        [Fact]
        public void Delete_GET_NullId_ReturnsBadRequest()
        {
            var result = _controller.Delete(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Delete_GET_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Delete(99999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Delete_GET_ValidId_ReturnsViewWithInstructor()
        {
            var instructor = _context.Instructors.First();

            var result = _controller.Delete(instructor.ID) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Instructor>(result.Model);
            Assert.Equal(instructor.ID, model.ID);
        }

        #endregion

        #region Delete POST

        [Fact]
        public void DeleteConfirmed_ValidId_RedirectsToIndex()
        {
            var instructor = _context.Instructors
                .Include(i => i.OfficeAssignment)
                .First();

            var result = _controller.DeleteConfirmed(instructor.ID) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
        }

        [Fact]
        public void DeleteConfirmed_ValidId_RemovesFromDatabase()
        {
            var instructor = _context.Instructors
                .Include(i => i.OfficeAssignment)
                .First();
            var countBefore = _context.Instructors.Count();
            var id = instructor.ID;

            _controller.DeleteConfirmed(id);

            Assert.Equal(countBefore - 1, _context.Instructors.Count());
        }

        [Fact]
        public void DeleteConfirmed_ClearsDepartmentAdministrator()
        {
            // Find an instructor that is a department administrator
            var dept = _context.Departments.First();
            var instructorId = dept.InstructorID.Value;
            var instructor = _context.Instructors
                .Include(i => i.OfficeAssignment)
                .Single(i => i.ID == instructorId);

            _controller.DeleteConfirmed(instructorId);

            var updatedDept = _context.Departments.Find(dept.DepartmentID);
            Assert.Null(updatedDept.InstructorID);
        }

        #endregion
    }
}

