using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.EntityFrameworkCore;
using System;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests
{
    public class SchoolContextTests : IDisposable
    {
        private readonly SchoolContext _context;

        public SchoolContextTests()
        {
            _context = TestDbContextFactory.CreateSeeded();
        }

        public void Dispose()
        {
            _context.Dispose();
        }

        [Fact]
        public void Context_HasStudents()
        {
            Assert.Equal(3, _context.Students.Count());
        }

        [Fact]
        public void Context_HasInstructors()
        {
            Assert.Equal(2, _context.Instructors.Count());
        }

        [Fact]
        public void Context_HasDepartments()
        {
            Assert.Equal(2, _context.Departments.Count());
        }

        [Fact]
        public void Context_HasCourses()
        {
            Assert.Equal(2, _context.Courses.Count());
        }

        [Fact]
        public void Context_HasEnrollments()
        {
            Assert.Equal(2, _context.Enrollments.Count());
        }

        [Fact]
        public void Context_HasCourseAssignments()
        {
            Assert.True(_context.CourseAssignments.Any());
        }

        [Fact]
        public void Context_HasOfficeAssignments()
        {
            Assert.True(_context.OfficeAssignments.Any());
        }

        [Fact]
        public void Context_CourseAssignment_CompositeKey()
        {
            var ca = _context.CourseAssignments.First();
            var found = _context.CourseAssignments.Find(ca.CourseID, ca.InstructorID);
            Assert.NotNull(found);
        }

        [Fact]
        public void Context_Student_CanBeAdded()
        {
            var student = new Student
            {
                FirstMidName = "Test",
                LastName = "Student",
                EnrollmentDate = DateTime.Now
            };

            _context.Students.Add(student);
            _context.SaveChanges();

            Assert.NotEqual(0, student.ID);
            Assert.Equal(4, _context.Students.Count());
        }

        [Fact]
        public void Context_Enrollment_RelationshipsWork()
        {
            var enrollment = _context.Enrollments
                .Include(e => e.Student)
                .Include(e => e.Course)
                .First();

            Assert.NotNull(enrollment.Student);
            Assert.NotNull(enrollment.Course);
        }

        [Fact]
        public void Context_Department_InstructorRelationship()
        {
            var dept = _context.Departments
                .Include(d => d.Administrator)
                .First();

            Assert.NotNull(dept.Administrator);
        }

        [Fact]
        public void Context_Instructor_OfficeAssignmentRelationship()
        {
            var instructor = _context.Instructors
                .Include(i => i.OfficeAssignment)
                .Single(i => i.LastName == "Fakhouri");

            Assert.NotNull(instructor.OfficeAssignment);
            Assert.Equal("Smith 17", instructor.OfficeAssignment.Location);
        }
    }
}

